"use client";

import type { CSSProperties } from "react";
import { useEffect, useMemo, useState } from "react";

const BOARD_SIZE = 320;
const TARGET_SIZE = 56;
const GAME_DURATION = 20;

type Position = {
  x: number;
  y: number;
};

function randomPosition(): Position {
  return {
    x: Math.floor(Math.random() * (BOARD_SIZE - TARGET_SIZE)),
    y: Math.floor(Math.random() * (BOARD_SIZE - TARGET_SIZE)),
  };
}

export default function Home() {
  const [score, setScore] = useState(0);
  const [timeLeft, setTimeLeft] = useState(GAME_DURATION);
  const [isRunning, setIsRunning] = useState(false);
  const [bestScore, setBestScore] = useState(0);
  const [targetPosition, setTargetPosition] = useState<Position>(() =>
    randomPosition()
  );

  useEffect(() => {
    const savedScore = window.localStorage.getItem("tap-target-best-score");
    if (savedScore) {
      setBestScore(Number(savedScore));
    }
  }, []);

  useEffect(() => {
    if (!isRunning) {
      return;
    }

    if (timeLeft === 0) {
      setIsRunning(false);
      if (score > bestScore) {
        setBestScore(score);
        window.localStorage.setItem("tap-target-best-score", String(score));
      }
      return;
    }

    const timer = window.setTimeout(() => {
      setTimeLeft((current) => current - 1);
    }, 1000);

    return () => window.clearTimeout(timer);
  }, [bestScore, isRunning, score, timeLeft]);

  const statusText = useMemo(() => {
    if (isRunning) {
      return "Nhanh tay click vào mục tiêu đang nhảy trên bàn chơi.";
    }

    if (timeLeft === 0) {
      return "Hết giờ. Bấm choi lai de thu pha ky luc.";
    }

    return "Bam bat dau de choi 20 giay.";
  }, [isRunning, timeLeft]);

  function startGame() {
    setScore(0);
    setTimeLeft(GAME_DURATION);
    setTargetPosition(randomPosition());
    setIsRunning(true);
  }

  function hitTarget() {
    if (!isRunning) {
      return;
    }

    setScore((current) => current + 1);
    setTargetPosition(randomPosition());
  }

  return (
    <main className="arcade-page">
      <section className="arcade-card">
        <p className="arcade-kicker">Next.js mini game</p>
        <h1>Tap Target</h1>
        <p className="arcade-copy">{statusText}</p>

        <div className="arcade-stats" aria-label="Thong tin tran dau">
          <div>
            <span>Diem</span>
            <strong>{score}</strong>
          </div>
          <div>
            <span>Thoi gian</span>
            <strong>{timeLeft}s</strong>
          </div>
          <div>
            <span>Ky luc</span>
            <strong>{bestScore}</strong>
          </div>
        </div>

        <div
          className={`arcade-board${isRunning ? " is-running" : ""}`}
          style={
            {
              "--target-x": `${targetPosition.x}px`,
              "--target-y": `${targetPosition.y}px`,
            } as CSSProperties
          }
        >
          <button
            type="button"
            className="arcade-target"
            onClick={hitTarget}
            disabled={!isRunning}
            aria-label="Muc tieu"
          >
            +1
          </button>

          {!isRunning && (
            <div className="arcade-overlay">
              <button type="button" className="arcade-start" onClick={startGame}>
                {timeLeft === 0 ? "Choi lai" : "Bat dau"}
              </button>
            </div>
          )}
        </div>
      </section>
    </main>
  );
}
